1	`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
2	`include "rvv_backend.svh"
3	`endif
4	`ifndef DIV_DEFINE_SVH
5	`include "rvv_backend_div.svh"
6	`endif
7	`ifndef RVV_ASSERT__SVH
8	`include "rvv_backend_sva.svh"
9	`endif
10	
11	module rvv_backend_div_unit_divider
12	(
13	  clk,
14	  rst_n,
15	  div_valid,
16	  div_ready,
17	  opcode,
18	  src2_dividend,
19	  src1_divisor,
20	  result_quotient,
21	  result_remainder,
22	  result_valid,
23	  result_ready,
24	  trap_flush_rvv
25	);
26	//
27	// parameter
28	//
29	  parameter logic[7:0] DIV_WIDTH = `WORD_WIDTH;
30	
31	//
32	// interface signals
33	//
34	  // global signals
35	  input   logic                 clk;
36	  input   logic                 rst_n;
37	
38	  // opcode 
39	  input   DIV_SIGN_SRC_e        opcode;
40	
41	  // operand 
42	  input   logic                 div_valid;
43	  output  logic                 div_ready;
44	  input   logic [DIV_WIDTH-1:0] src2_dividend;
45	  input   logic [DIV_WIDTH-1:0] src1_divisor;
46	
47	  // result
48	  output  logic [DIV_WIDTH-1:0] result_quotient;
49	  output  logic [DIV_WIDTH-1:0] result_remainder;
50	  output  logic                 result_valid;
51	  input   logic                 result_ready;
52	
53	  // trap-flush
54	  input   logic                 trap_flush_rvv;  
55	
56	//
57	// internal signals
58	//
59	  // FSM
60	  typedef enum logic [1:0] {DIV_IDLE, DIV_WORKING, DIV_PRINT} state_e;
61	  state_e                       state, next_state;
62	  
63	  // number of leading zero bits
64	  logic [$clog2(DIV_WIDTH):0]   cnt_clzb;
65	  logic [$clog2(DIV_WIDTH):0]   clzb;
66	  logic [$clog2(DIV_WIDTH):0]   count_shift;
67	
68	  // processing round for divider
69	  logic [DIV_WIDTH-1:0]         quotient_r1;
70	  logic [DIV_WIDTH-1:0]         quotient_r2;
71	  logic [DIV_WIDTH-1:0]         quotient_r3;
72	  logic [DIV_WIDTH-1:0]         remainder_r1;
73	  logic [DIV_WIDTH-1:0]         remainder_r2;
74	  logic [DIV_WIDTH-1:0]         remainder_r3;
75	  logic [$clog2(DIV_WIDTH):0]   count_r1;
76	  logic [$clog2(DIV_WIDTH):0]   count_r2;
77	  logic [$clog2(DIV_WIDTH):0]   count_r3;
78	
79	  // register signals
80	  logic                         dividend_en;
81	  logic [DIV_WIDTH-1:0]         dividend_d;
82	  logic [DIV_WIDTH-1:0]         dividend_q;
83	  logic                         divisor_en;
84	  logic [DIV_WIDTH-1:0]         divisor_d;
85	  logic [DIV_WIDTH-1:0]         divisor_q;
86	  logic                         quotient_en;
87	  logic [DIV_WIDTH-1:0]         quotient_d;
88	  logic [DIV_WIDTH-1:0]         quotient_q;
89	  logic                         remainder_en;
90	  logic [DIV_WIDTH-1:0]         remainder_d;
91	  logic [DIV_WIDTH-1:0]         remainder_q;
92	  logic                         count_en;
93	  logic [$clog2(DIV_WIDTH):0]   count_d;
94	  logic [$clog2(DIV_WIDTH):0]   count_q;
95	  logic                         q_sgn_en;
96	  logic                         q_sgn_d;
97	  logic                         q_sgn_q;
98	  logic                         r_sgn_en;
99	  logic                         r_sgn_d;
100	  logic                         r_sgn_q;
101	`ifdef TB_SUPPORT
102	  logic                         res_reuse_valid_p0;
103	`endif
104	  
105	//
106	// register
107	//
108	  // dividend
109	  cdffr
110	  #(
111	    .T      (logic [DIV_WIDTH-1:0])
112	  )
113	  dividend
114	  (
115	    .clk    (clk),
116	    .rst_n  (rst_n),
117	    .e      (dividend_en),
118	    .c      (trap_flush_rvv),
119	    .d      (dividend_d),
120	    .q      (dividend_q)
121	  );
122	  // divisor
123	  cdffr
124	  #(
125	    .T      (logic [DIV_WIDTH-1:0])
126	  )
127	  divisor
128	  (
129	    .clk    (clk),
130	    .rst_n  (rst_n),
131	    .e      (divisor_en),
132	    .c      (trap_flush_rvv),
133	    .d      (divisor_d),
134	    .q      (divisor_q)
135	  );
136	  // quotient
137	  cdffr
138	  #(
139	    .T      (logic [DIV_WIDTH-1:0])
140	  )
141	  quotient
142	  (
143	    .clk    (clk),
144	    .rst_n  (rst_n),
145	    .e      (quotient_en),
146	    .c      (trap_flush_rvv),
147	    .d      (quotient_d),
148	    .q      (quotient_q)
149	  );
150	  // remainder
151	  cdffr
152	  #(
153	    .T      (logic [DIV_WIDTH-1:0])
154	  )
155	  remainder
156	  (
157	    .clk    (clk),
158	    .rst_n  (rst_n),
159	    .e      (remainder_en),
160	    .c      (trap_flush_rvv),
161	    .d      (remainder_d),
162	    .q      (remainder_q)
163	  );
164	  // count
165	  edff
166	  #(
167	  .T        (logic [$clog2(DIV_WIDTH):0])
168	  )
169	  count
170	  (
171	    .clk    (clk),
172	    .rst_n  (rst_n),
173	    .e      (count_en),
174	    .d      (count_d),
175	    .q      (count_q)
176	  );
177	  // record quotient sgn-bit
178	  cdffr
179	  q_sgn
180	  (
181	    .clk    (clk),
182	    .rst_n  (rst_n),
183	    .e      (q_sgn_en),
184	    .c      (trap_flush_rvv),
185	    .d      (q_sgn_d),
186	    .q      (q_sgn_q)
187	  );
188	  // record remainder sgn-bit
189	  cdffr
190	  r_sgn
191	  (
192	    .clk    (clk),
193	    .rst_n  (rst_n),
194	    .e      (r_sgn_en),
195	    .c      (trap_flush_rvv),
196	    .d      (r_sgn_d),
197	    .q      (r_sgn_q)
198	  );
199	
200	//
201	// FSM
202	//
203	  edff
204	  #(
205	  .T        (state_e),
206	  .INIT     (DIV_IDLE)
207	  )
208	  fsm_state
209	  (
210	    .clk    (clk),
211	    .rst_n  (rst_n),
212	    .e      (next_state!=state),
213	    .d      (next_state),
214	    .q      (state)
215	  );
216	  
217	  // state transition
218	  always_comb begin
219	    next_state = state;
220	
221	    case(state)
222	      DIV_IDLE: begin
223	        if(div_valid&(!trap_flush_rvv)) begin
224	          if ((count_en=='b1)&(count_d=='b1))
225	            next_state = DIV_PRINT;
226	          else
227	            next_state = DIV_WORKING;
228	        end
229	        else
230	          next_state = DIV_IDLE;
231	      end
232	      DIV_WORKING: begin
233	        if(div_valid&(!trap_flush_rvv)) begin
234	          if ((count_en=='b1)&(count_d=='b1))
235	            next_state = DIV_PRINT;
236	          else
237	            next_state = DIV_WORKING;
238	        end
239	        else
240	          next_state = DIV_IDLE;
241	      end
242	      DIV_PRINT: begin
243	        if (div_valid&(!result_ready)&(!trap_flush_rvv))
244	          next_state = DIV_PRINT;
245	        else
246	          next_state = DIV_IDLE;
247	      end
248	    endcase
249	  end
250	
251	  // count leading zero
252	  generate 
253	    if (DIV_WIDTH== 'd`WORD_WIDTH) begin
254	      assign clzb = f_clzb32(dividend_d);
255	      assign count_shift = 'd33 - clzb;            
256	    end
257	    else if (DIV_WIDTH== 'd`HWORD_WIDTH) begin
258	      assign clzb = f_clzb16(dividend_d);
259	      assign count_shift = 'd17 - clzb;            
260	    end
261	    else if (DIV_WIDTH== 'd`BYTE_WIDTH) begin
262	      assign clzb = f_clzb8(dividend_d);
263	      assign count_shift = 'd9 - clzb;            
264	    end
265	  endgenerate
266	
267	  // div is ready to receive a new uop
268	  assign div_ready = state==DIV_IDLE; 
269	  
270	  // FSM
271	  always_comb begin
272	    // initial
273	    dividend_en      = 'b0;
274	    dividend_d       = 'b0;
275	    divisor_en       = 'b0;
276	    divisor_d        = 'b0;
277	    quotient_en      = 'b0;
278	    quotient_d       = 'b0;
279	    remainder_en     = 'b0;
280	    remainder_d      = 'b0;
281	    count_en         = 'b0;
282	    count_d          = 'b0;
283	    q_sgn_en         = 'b0;
284	    q_sgn_d          = 'b0;         
285	    r_sgn_en         = 'b0;
286	    r_sgn_d          = 'b0;
287	    cnt_clzb         = 'b0;
288	    quotient_r1      = 'b0;
289	    quotient_r2      = 'b0;
290	    quotient_r3      = 'b0;
291	    remainder_r1     = 'b0;
292	    remainder_r2     = 'b0;
293	    remainder_r3     = 'b0;
294	    count_r1         = 'b0;
295	    count_r2         = 'b0;
296	    count_r3         = 'b0;
297	    result_quotient  = 'b0;
298	    result_remainder = 'b0;
299	    result_valid     = 'b0;
300	`ifdef TB_SUPPORT
301	    res_reuse_valid_p0 = 'b0;
302	`endif
303	
304	    case(state)
305	      DIV_IDLE: begin
306	        if(div_valid) begin
307	          // check whether divisor is 0
308	          if(src1_divisor=='b0) begin
309	            dividend_en = 'b1;
310	            dividend_d  = 'b0;
311	
312	            divisor_en = 'b1;
313	            divisor_d  = 'b0;
314	
315	            quotient_en = 'b1;
316	            quotient_d  = '1;
317	
318	            remainder_en = 'b1;
319	            remainder_d  = src2_dividend;
320	
321	            q_sgn_en = 'b1;
322	            q_sgn_d  = 'b0;
323	
324	            r_sgn_en = 'b1;
325	            r_sgn_d  = 'b0;
326	
327	            count_en = 'b1;
328	            count_d  = 'b1;
329	          end
330	          // check whether is -2^(WIDTH-1)/-1. The result will overflow.
331	          else if ((opcode==DIV_SIGN)&(src2_dividend=={1'b1,{(DIV_WIDTH-1){1'b0}}})&(src1_divisor=='1)) begin
332	            dividend_en = 'b1;
333	            dividend_d  = 'b0;
334	
335	            divisor_en = 'b1;
336	            divisor_d  = 'b0;
337	
338	            quotient_en = 'b1;
339	            quotient_d  = {1'b1,{(DIV_WIDTH-1){1'b0}}};
340	
341	            remainder_en = 'b1;
342	            remainder_d  = 'b0;
343	
344	            q_sgn_en = 'b1;
345	            q_sgn_d  = 'b0;
346	
347	            r_sgn_en = 'b1;
348	            r_sgn_d  = 'b0;
349	
350	            count_en = 'b1;
351	            count_d  = 'b1;
352	          end
353	          // start to initialize
354	          else begin
355	            if(opcode==DIV_SIGN) begin
356	              // convert signed data to unsigned data
357	              dividend_d  = src2_dividend[DIV_WIDTH-1] ? (~(src2_dividend)+1) : src2_dividend;
358	              divisor_d  = src1_divisor[DIV_WIDTH-1] ? (~(src1_divisor )+1) : src1_divisor;
359	              
360	              q_sgn_d   = src2_dividend[DIV_WIDTH-1]^src1_divisor[DIV_WIDTH-1];
361	              r_sgn_d   = src2_dividend[DIV_WIDTH-1];
362	            end
363	            else begin
364	              dividend_d  = src2_dividend;
365	              divisor_d  = src1_divisor;
366	
367	              q_sgn_d  = 'b0;
368	              r_sgn_d  = 'b0;
369	            end
370	
371	            // check whether dividend and divisor equal to last source data
372	            if ((dividend_d==dividend_q)&(divisor_d==divisor_q)&(q_sgn_d==q_sgn_q)&(r_sgn_d==r_sgn_q)) begin
373	              dividend_en = 'b0; 
374	              divisor_en = 'b0;
375	
376	              q_sgn_en  = 'b0;
377	              r_sgn_en  = 'b0;
378	              
379	              count_en = 'b1;
380	              count_d  = 'b1;
381	
382	`ifdef TB_SUPPORT
383	              res_reuse_valid_p0 = 1'b1;
384	`endif
385	            end
386	            else begin
387	              dividend_en = 'b1; 
388	              divisor_en = 'b1;
389	
390	              q_sgn_en  = 'b1;
391	              r_sgn_en  = 'b1;
392	
393	              // count leading zero bits in dividend
394	              cnt_clzb  = clzb;
395	              count_en  = 'b1;
396	              count_d   = count_shift;            
397	
398	              // initialize quotient and remainder
399	              quotient_en = 'b1;   
400	              quotient_d  = dividend_d<<cnt_clzb;
401	
402	              remainder_en = 'b1;
403	              remainder_d  = 'b0;
404	            end
405	          end
406	        end
407	      end
408	      DIV_WORKING: begin
409	        if(div_valid) begin
410	          // processing
411	          f_div_step (remainder_q ,quotient_q ,divisor_q,remainder_r1,quotient_r1);
412	          f_div_step (remainder_r1,quotient_r1,divisor_q,remainder_r2,quotient_r2);
413	          f_div_step (remainder_r2,quotient_r2,divisor_q,remainder_r3,quotient_r3);
414	          
415	          count_r1 = count_q - 'd1;
416	          count_r2 = count_q - 'd2;
417	          count_r3 = count_q - 'd3;
418	          
419	          quotient_en = 'b1;   
420	          remainder_en = 'b1;
421	          count_en = 'b1;
422	
423	          case({{($clog2(DIV_WIDTH)-1){1'b0}},1'b1})
424	            count_r1: begin
425	              quotient_d  = quotient_r1;
426	              remainder_d = remainder_r1;
427	              count_d     = 'b1; 
428	            end
429	            count_r2: begin
430	              quotient_d  = quotient_r2;
431	              remainder_d = remainder_r2;
432	              count_d     = 'b1;            
433	            end
434	            default: begin
435	              quotient_d  = quotient_r3;
436	              remainder_d = remainder_r3;
437	              count_d     = count_r3;            
438	            end
439	          endcase
440	        end  
441	      end
442	      // get result to ouput and wait for ready signal
443	      DIV_PRINT: begin
444	        result_valid = 'b1;
445	        
446	        result_quotient  = q_sgn_q ? ((~quotient_q )+'d1) : quotient_q;
447	        result_remainder = r_sgn_q ? ((~remainder_q)+'d1) : remainder_q;
448	    
449	        count_en = result_ready;
450	        count_d  = 'b0;
451	      end
452	    endcase
453	  end
454	
455	//
456	// function unit
457	//
458	  // count leading zero bits
459	  function [1:0] f_clzb2
460	  (   
461	    input logic [1:0] src
462	  );
463	    
464	    if (src[1])
465	      f_clzb2 = 2'b00;
466	    else if (src[0])
467	      f_clzb2 = 2'b01;
468	    else
469	      f_clzb2 = 2'b10;
470	  endfunction
471	
472	  function [2:0] f_clzb4
473	  (
474	    input logic [3:0] src
475	  );
476	
477	    logic [1:0] hi;
478	    logic [1:0] lo;
479	
480	    hi = f_clzb2(src[3:2]);
481	    lo = f_clzb2(src[1:0]);
482	    if ((hi[1]==1'b1)&(lo[1]==1'b1))
483	      f_clzb4 = 3'b100;
484	    else if (hi[1]==1'b0)
485	      f_clzb4 = {1'b0,hi};
486	    else
487	      f_clzb4 = {2'b01,lo[0]};
488	  endfunction
489	
490	  function [3:0] f_clzb8
491	  (
492	    input logic [7:0] src
493	  );
494	
495	    logic [2:0] hi;
496	    logic [2:0] lo;
497	
498	    hi = f_clzb4(src[7:4]);
499	    lo = f_clzb4(src[3:0]);
500	    if ((hi[2]==1'b1)&(lo[2]==1'b1))
501	      f_clzb8 = 4'b1000;
502	    else if (hi[2]==1'b0)
503	      f_clzb8 = {1'b0,hi};
504	    else
505	      f_clzb8 = {2'b01,lo[1:0]};
506	  endfunction
507	
508	  function [4:0] f_clzb16
509	  (
510	    input logic [15:0] src
511	  );
512	
513	    logic [3:0] hi;
514	    logic [3:0] lo;
515	
516	    hi = f_clzb8(src[15:8]);
517	    lo = f_clzb8(src[7:0]);
518	    if ((hi[3]==1'b1)&(lo[3]==1'b1))
519	      f_clzb16 = 5'b1_0000;
520	    else if (hi[3]==1'b0)
521	      f_clzb16 = {1'b0,hi};
522	    else
523	      f_clzb16 = {2'b01,lo[2:0]};
524	  endfunction
525	
526	  function [5:0] f_clzb32  
527	  (
528	    input logic [31:0] src
529	  );
530	    
531	    logic [4:0] hi;
532	    logic [4:0] lo;
533	
534	    hi = f_clzb16(src[31:16]);
535	    lo = f_clzb16(src[15:0]);
536	    if ((hi[4]==1'b1)&(lo[4]==1'b1))
537	      f_clzb32 = 6'b10_0000;
538	    else if (hi[4]==1'b0)
539	      f_clzb32 = {1'b0,hi};
540	    else
541	      f_clzb32 = {2'b01,lo[3:0]};
542	  endfunction
543	
544	  // div step: shift and subtract
545	  function void f_div_step
546	  (
547	    input  logic [DIV_WIDTH-1:0] remainder_in,
548	    input  logic [DIV_WIDTH-1:0] quotient_in,
549	    input  logic [DIV_WIDTH-1:0] divisor_in,
550	    output logic [DIV_WIDTH-1:0] remainder_out,
551	    output logic [DIV_WIDTH-1:0] quotient_out
552	  );
553	
554	    logic [DIV_WIDTH-1:0] remainder_tmp;
555	    logic [DIV_WIDTH  :0] diff;
556	    
557	    remainder_tmp = {remainder_in[DIV_WIDTH-2:0],quotient_in[DIV_WIDTH-1]};
558	    diff = {1'b0,remainder_tmp} - {1'b0,divisor_in};
559	
560	    if (diff[DIV_WIDTH]) begin
561	      remainder_out = remainder_tmp;
562	      quotient_out  = {quotient_in[DIV_WIDTH-2:0],1'b0};
563	    end
564	    else begin
565	      remainder_out = diff[DIV_WIDTH-1:0];
566	      quotient_out  = {quotient_in[DIV_WIDTH-2:0],1'b1};
567	    end
568	  endfunction
569	
570	endmodule
571

