922	                      result_data[(4*i+2)*`BYTE_WIDTH +: `BYTE_WIDTH] = 'h7f;
923	                    else if (underoverflow[4*i+2])
924	                      result_data[(4*i+2)*`BYTE_WIDTH +: `BYTE_WIDTH] = 'h80;
925	                    else
926	                      result_data[(4*i+2)*`BYTE_WIDTH +: `BYTE_WIDTH] = round16[4*(i-`VLENW/2)+2][`BYTE_WIDTH-1 : 0];
927	
