934	                  end
935	                end
936	                EEW32: begin
937	                  if (i<`VLENW/2) begin
938	                    if (upoverflow[4*i+1])
939	                      result_data[(2*i)*`HWORD_WIDTH +: `HWORD_WIDTH] = 'h7fff;
940	                    else if (underoverflow[4*i+1])
941	                      result_data[(2*i)*`HWORD_WIDTH +: `HWORD_WIDTH] = 'h8000;
942	                    else
943	                      result_data[(2*i)*`HWORD_WIDTH +: `HWORD_WIDTH] = round32[2*i][`HWORD_WIDTH-1 : 0];
944	
945	                    if (upoverflow[4*i+3])
946	                      result_data[(2*i+1)*`HWORD_WIDTH +: `HWORD_WIDTH] = 'h7fff;
947	                    else if (underoverflow[4*i+3])
948	                      result_data[(2*i+1)*`HWORD_WIDTH +: `HWORD_WIDTH] = 'h8000;
949	                    else
950	                      result_data[(2*i+1)*`HWORD_WIDTH +: `HWORD_WIDTH] = round32[2*i+1][`HWORD_WIDTH-1 : 0];
951	                  end
