`ifndef HDL_VERILOG_RVV_DESIGN_RVV_SVH
`include "rvv_backend.svh"
`endif
`ifndef RVV_ASSERT__SVH
`include "rvv_backend_sva.svh"
`endif

module rvv_backend_alu_unit_execution_p1
(
  clk,
  rst_n,
  alu_uop_valid,
  alu_uop,
  result_valid,
  result,
  trap_flush_rvv
);
  parameter CMP_SUPPORT = 1'b0;

//
// interface signals
//
  // global signal
  input   logic           clk;
  input   logic           rst_n;
  // ALU RS handshake signals
  input   logic           alu_uop_valid;
  input   PIPE_DATA_t     alu_uop;
  // ALU send result signals to ROB
  output  logic           result_valid;
  output  PU2ROB_t        result;
  // trap-flush
  input   logic           trap_flush_rvv; 

//
// internal signals
//  
  // ALU_RS_t struct signals
  ADDSUB_e                                opcode;
  FUNCT6_u                                uop_funct6;
  logic   [`FUNCT3_WIDTH-1:0]             uop_funct3;
  logic   [`VSTART_WIDTH-1:0]             vstart;
  logic   [`VL_WIDTH-1:0]                 vl;       
  logic                                   vm;       
  RVVXRM                                  vxrm;       
  logic   [`VLEN-1:0]                     v0_data;
  logic   [`VLEN-1:0]                     vd_data;           
  EEW_e                                   vs2_eew;
  logic        	                          last_uop_valid;
  logic   [$clog2(`EMUL_MAX)-1:0]         uop_index;   

  logic                                   is_cmp;
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   src2_data;
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   src1_data;  
  logic   [`VLENB-1:0]                    src2_sgn;
  logic   [`VLENB-1:0]                    src1_sgn;
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   product8;
  logic   [`VLENH-1:0][`HWORD_WIDTH-1:0]  product16;
  logic   [`VLENW-1:0][`WORD_WIDTH-1:0]   product32;
  logic   [`VLENB-1:0]                    cout8;
  logic   [`VLENH-1:0]                    cout16;
  logic   [`VLENW-1:0]                    cout32;  
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   round8_src;
  logic   [`VLENH-1:0][`HWORD_WIDTH-1:0]  round16_src;
  logic   [`VLENW-1:0][`WORD_WIDTH-1:0]   round32_src;
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   round8;
  logic   [`VLENH-1:0][`HWORD_WIDTH-1:0]  round16;
  logic   [`VLENW-1:0][`WORD_WIDTH-1:0]   round32;
  logic   [`VLENB-1:0]                    addu_upoverflow;
  logic   [`VLENB-1:0]                    add_upoverflow;
  logic   [`VLENB-1:0]                    add_underoverflow;
  logic   [`VLENB-1:0]                    subu_underoverflow;
  logic   [`VLENB-1:0]                    sub_upoverflow;
  logic   [`VLENB-1:0]                    sub_underoverflow;
  logic   [`VLENB-1:0][`BYTE_WIDTH-1:0]   result_minmax8;
  logic   [`VLENH-1:0][`HWORD_WIDTH-1:0]  result_minmax16;
  logic   [`VLENW-1:0][`WORD_WIDTH-1:0]   result_minmax32;
  logic   [`VLEN-1:0]                     result_data;   // regular data for EEW_vd = 8b,16b,32b
  genvar                                  j;

  // for CMP
  logic   [`VLEN-1:0]                     vstart_elements_tmp;
  logic   [`VLEN-1:0]                     vstart_elements;
  logic   [`VLEN-1:0]                     tail_elements_tmp;
  logic   [`VLEN-1:0]                     tail_elements;
  logic   [`VLEN-1:0]                     cmp_tmp;
  logic   [`VLEN-1:0]                     cmp;
  logic   [27:0]                          cmp_en;
  logic   [28*`VLENW-1:0]                 cmp_d1;

      .fifo_data    (),
      .wptr         (),
      .rptr         (),
      .entry_count  ()
  );
  // ready signal for LSU
  assign uop_lsu_ready = ~lsu_res_almost_full;
  assign uop_lsu_ready_rvv2lsu = is_trapping ? 'b0 : uop_lsu_ready;

// PU, Process unit
  // ALU
  assign uop_valid_rs2alu = ~fifo_almost_empty_rs2alu;
  rvv_backend_alu #(
  ) u_alu (
    // ALU_RS to ALU
      .clk                        (clk),
      .rst_n                      (rst_n),
      .pop                        (pop_alu2rs),
      .uop_valid                  (uop_valid_rs2alu),
      .uop                        (uop_rs2alu),
    // ALU to ROB  
      .result_valid               (res_valid_alu),
      .result                     (res_alu),
      .result_ready               (res_ready_alu),
    // trap-flush
      .trap_flush_rvv             (trap_flush_rvv)
  );

  // PMTRDT
  rvv_backend_pmtrdt #(
  ) u_pmtrdt (
      .clk                        (clk),
      .rst_n                      (rst_n),
    // PMTRDT_RS to PMTRDT
      .pop_ex2rs                  (pop_pmtrdt2rs),
      .pmtrdt_uop_rs2ex           (uop_rs2pmtrdt),
      .fifo_almost_empty_rs2ex    (fifo_almost_empty_rs2pmtrdt),
    // PMT to VRF
      .rd_index_pmt2vrf           (rd_index_pmt2vrf),
      .rd_data_vrf2pmt            (rd_data_vrf2pmt),
    // PMTRDT to ROB
      .result_valid_ex2rob        (res_valid_pmtrdt),
      .result_ex2rob              (res_pmtrdt),
      .result_ready_rob2ex        (res_ready_pmtrdt),
    // MISC
      .rob_entry_rob2rt           (rob_entry_rob2rt),
    // trap-flush
      .trap_flush_rvv             (trap_flush_rvv)
  );

  // MULMAC
  rvv_backend_mulmac #(
  ) u_mulmac (
      .clk                        (clk),
      .rst_n                      (rst_n),
      .trap_flush_rvv             (trap_flush_rvv),
      .uop_valid_rs2ex            (~fifo_almost_empty_rs2mul),
      .mac_uop_rs2ex              (uop_rs2mul),
      .pop                        (pop_mul2rs),
      .res_valid_ex2rob           (res_valid_mul),
      .res_ex2rob                 (res_mul),
      .res_ready_rob2ex           (res_ready_mul)
  );

  // DIV
  assign uop_valid_rs2div = ~fifo_almost_empty_rs2div;
  rvv_backend_div u_div
  (  
    .clk                          (clk),
    .rst_n                        (rst_n),
    // DIV_RS to DIV
    .pop                          (pop_div2rs),
    .uop_valid                    (uop_valid_rs2div),
    .uop                          (uop_rs2div),
    // DIV to ROB
    .result_valid                 (res_valid_div),
    .result                       (res_div),
    .result_ready                 (res_ready_div),
    // trap-flush
    .trap_flush_rvv               (trap_flush_rvv)
  );

`ifdef ZVE32F_ON
  // FMA
  assign uop_valid_rs2falu = ~fifo_almost_empty_rs2falu;
  rvv_backend_falu u_falu
  (  
    .clk                          (clk),
    .rst_n                        (rst_n),
    // FMA_RS to FMA
    .pop                          (pop_falu2rs),
    .uop_valid                    (uop_valid_rs2falu),
    .uop                          (uop_rs2falu),
    // FMA to ROB
    .result_valid                 (res_valid_falu),
    .result                       (res_falu),
    .result_ready                 (res_ready_falu),
    // trap-flush
    .trap_flush_rvv               (trap_flush_rvv)
  );
 `endif

  // LSU remap
  assign mapinfo_valid = ~mapinfo_almost_empty;
  assign lsu_res_valid = ~lsu_res_almost_empty;
  rvv_backend_lsu_remap
  u_lsu_remap
  (
    .mapinfo_valid                (mapinfo_valid),
    .mapinfo                      (mapinfo),
    .pop_mapinfo                  (pop_mapinfo),
    .lsu_res_valid                (lsu_res_valid),
    .lsu_res                      (lsu_res),
    .pop_lsu_res                  (pop_lsu_res),
    .result_valid                 (res_valid_lsu),
    .result                       (res_lsu),      
    .result_ready                 (res_ready_lsu),
    .trap_valid_rmp2rob           (trap_valid_rmp2rob),
    .trap_rob_entry_rmp2rob       (trap_rob_entry_rmp2rob),
    .trap_ready_rob2rmp           (trap_ready_rob2rmp)  
  );

  assign res_valid_pu2arb = {
                            `ifdef ZVE32F_ON
                             res_valid_falu,
                            `endif
                             res_valid_div,
                             res_valid_pmtrdt,  
                             res_valid_mul,
                             res_valid_alu,

